#include <bits/stdc++.h>
using namespace std;
int n,m,x,a[1003][1003],f[1003][1003][11][2],ans=1e9;
int main(){
    scanf("%d%d%d",&n,&m,&x);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            scanf("%d",&a[i][j]);
            f[i][j][0][0]=f[i][j][0][1]=a[i][j];
            for(int k=1;(1<<k)<=min(i,j);k++){
                int l=(1<<(k-1));
                f[i][j][k][0]=min(f[i][j][k-1][0],min(f[i][j-l][k-1][0],min(f[i-l][j][k-1][0],f[i-l][j-l][k-1][0])));
                f[i][j][k][1]=max(f[i][j][k-1][1],max(f[i][j-l][k-1][1],max(f[i-l][j][k-1][1],f[i-l][j-l][k-1][1])));
            }
        }
    for(int i=x;i<=n;i++)
        for(int j=x;j<=m;j++){
            int l=1<<(int)(log2(x)),num=log2(x),u,v;
            u=min(min(f[i][j][num][0],f[i-x+l][j-x+l][num][0]),min(f[i][j-x+l][num][0],f[i-x+l][j][num][0]));
            v=max(max(f[i][j][num][1],f[i-x+l][j-x+l][num][1]),max(f[i][j-x+l][num][1],f[i-x+l][j][num][1]));
            ans=min(ans,v-u);
        }
    printf("%d",ans);
    return 0;
}
